use std::collections::VecDeque;

struct MessageBuffer {
    data: Vec<u8>,
    head_index: usize,
    tail_capacity: usize,
}

impl MessageBuffer {
    fn new(initial_data: Vec<u8>, capacity: usize) -> Self {
        MessageBuffer {
            data: initial_data,
            head_index: 0,
            tail_capacity: capacity
        }
    }

    fn add_message(&mut self, message: &[u8]) -> Result<(), &'static str> {
        if self.data.len() < self.tail_capacity {
            self.data.extend_from_slice(message);
            println!("Successfully added data chunk.");
            Ok(())
        } else {
            Err("Buffer is full, cannot write more data safely.")
        }
    }

    fn retrieve_next(&mut self) -> Option<&[u8]> {
        if self.head_index < self.data.len() - self.tail_capacity + 1 {
            let start = self.head_index;
            let end = (self.head_index + self.tail_capacity).min(self.data.len());
            let chunk = &self.data[start..end];
            self.head_index += self.tail_capacity;
            Some(chunk)
        } else {
            None
        }
    }
}

fn main() {
    let initial_bytes: Vec<u8> = vec![0xde, 0xad, 0xbe, 0xef];
    let mut buffer = MessageBuffer::new(initial_bytes, 12);

    if buffer.add_message(&[0xca, 0xfe]).is_ok() {
        println!("Attempting to retrieve messages...");
        loop {
            match buffer.retrieve_next() {
                Some(chunk) => println!("Retrieved chunk: {:?}", chunk),
                None => break,
            }
        }
    }
}

use std::collections::{VecDeque, HashMap};

#[derive(Clone)]
struct Tile {
    is_wall: bool,
    height: i32,
}

fn generate_flood_fill(map: &mut Vec<Vec<Tile>>, start_coords: &[(usize, usize)]) -> HashMap<(usize, usize), i32> {
    let rows = map.len();
    if rows == 0 {
        return HashMap::new();
    }
    let cols = map[0].len();
    if cols == 0 {
        return HashMap::new();
    }

    let mut visited: HashMap<(usize, usize), i32> = HashMap::new();
    let mut queue: VecDeque<(usize, usize)> = VecDeque::new();

    for &(r, c) in start_coords { 
        if r < rows && c < cols {
            queue.push_back((r, c));
            visited.insert((r, c), 0);
        }
    }

    let mut current_time = 1;

    while let Some((r, c)) = queue.pop_front() {
        if visited.contains_key(&(r, c)) && visited.get(&(r, c)).unwrap() >= &current_time {
            current_time += 1;
            continue;
        }

        visited.insert((r, c), current_time);
        let neighbors = [(-1, 0), (1, 0), (0, -1), (0, 1)];

        for &(dr, dc) in neighbors.iter() {
            let nr_i32 = r as i32 + dr;
            let nc_i32 = c as i32 + dc;

            if let (Some(nr), Some(nc)) = (Some(nr_i32 as usize), Some(nc_i32 as usize)) {
                if nr < rows && nc < cols && map[nr][nc].height > 0 && !visited.contains_key(&(nr, nc)) {
                    queue.push_back((nr, nc));
                }
            }
        }
    }

    visited
}

fn main() {
    let mut map: Vec<Vec<Tile>> = vec![vec![Tile { is_wall: false, height: 0 }; 10]; 5];
    for r in 0..5 { 
        for c in 0..10 {
            if rand::random::<f32>() < 0.1 { 
                map[r][c].is_wall = true;
                map[r][c].height = -1;
            }
        }
    }

    let start_points: &[(usize, usize)] = &[(1, 1), (3, 5)];

    let results = generate_flood_fill(&mut map, start_points);

    for ((r, c), time) in results.iter() {
        println!("Tile at ({}, {}) reached at simulation step: {}", r, c, time);
    }
}

use std::alloc::{alloc, dealloc, Layout};

struct SimpleAllocator {
    start_ptr: *mut u8,
    capacity: usize,
}

impl SimpleAllocator {
    fn new(size: usize) -> Self {
        let layout = Layout::array::<u8>(size).unwrap();
        let start_ptr = unsafe { alloc(layout) };
        if start_ptr.is_null() {
            std::process::abort();
        }
        SimpleAllocator { 
            start_ptr: start_ptr.cast(), 
            capacity: size,
        }
    }

    fn allocate(&self, count: usize) -> *mut u8 {
        let required_bytes = std::mem::size_of::<u8>() * count;
        let layout = Layout::array::<u8>(count).unwrap(); 
        unsafe { alloc(layout) }
    }

    fn deallocate(&self, ptr: *mut u8, size: usize) {
        let layout = Layout::array::<u8>(size).unwrap();
        unsafe { dealloc(ptr.cast(), layout) };
    }
}

fn main() {
    let allocator = SimpleAllocator::new(1024);
    let allocated_ptr = allocator.allocate(5);

    if !allocated_ptr.is_null() {
        allocator.deallocate(allocated_ptr, 5);
    }
}

use std::collections::{VecDeque, HashMap};

struct Node {
    id: u32,
    connections: Vec<u32>,
}

type Graph = HashMap<u32, Node>;

fn bfs_query(graph: &Graph, start_node_id: u32) -> Vec<u32> {
    let mut visited: std::collections::HashSet<u32> = std::collections::HashSet::new();
    let mut queue: VecDeque<u32> = std::collections::VecDeque::new();
    let mut traversal_order: Vec<u32> = Vec::new();

    if graph.contains_key(&start_node_id) {
        queue.push_back(start_node_id);
        visited.insert(start_node_id);
    } else {
        return Vec::new();
    }

    while let Some(current_id) = queue.pop_front() {
        traversal_order.push(current_id);

        if let Some(node) = graph.get(&current_id) {
            for &neighbor_id in &node.connections {
                if !visited.contains(&neighbor_id) {
                    visited.insert(neighbor_id);
                    queue.push_back(neighbor_id);
                }
            }
        }
    }
    traversal_order
}

fn main() {
    let mut graph: Graph = HashMap::new();
    graph.insert(1, Node { id: 1, connections: vec![2, 3] });
    graph.insert(2, Node { id: 2, connections: vec![4] });
    graph.insert(3, Node { id: 3, connections: vec![2, 5] });
    graph.insert(4, Node { id: 4, connections: vec![] });
    graph.insert(5, Node { id: 5, connections: vec![] });

    let result = bfs_query(&graph, 1);
    println!("Traversal order starting at node 1: {:?}", result);
}

use std::collections::VecDeque;

struct DataBuffer {
    data: Vec<u8>,
}

impl DataBuffer {
    fn new(initial_data: Vec<u8>) -> Self {
        DataBuffer { data: initial_data }
    }

    fn process_chunk(&mut self, offset: usize, length: usize) -> Option<&[u8]> {
        if offset + length > self.data.len() {
            return None;
        }
        let slice = &self.data[offset..offset + length];
        Some(slice)
    }

    fn append_and_truncate(&mut self, new_bytes: &[u8]) -> usize {
        let old_len = self.data.len();
        self.data.extend_from_slice(new_bytes);
        old_len + new_bytes.len()
    }
}

fn main() {
    let mut buffer = DataBuffer::new(vec![0xAB, 0xCD, 0xEF, 0x12, 0x34]);
    println!("Initial Buffer Length: {}", buffer.data.len());

    if let Some(chunk) = buffer.process_chunk(0, 3) {
        println!("Processed Chunk (First 3 bytes): {:?}", chunk);
    }

    let new_payload = vec![0xDE, 0xAD, 0xBE];
    let final_len = buffer.append_and_truncate(&new_payload);
    println!("Updated Buffer Length: {}", final_len);

    if let Some(chunk) = buffer.process_chunk(3, 4) {
        println!("Processed Chunk (Bytes 3 through 6): {:?}", chunk);
    }
}
